def solve(grid: Array[Array[Long]], x: Long, y: Long, k: Long): Array[Array[Long]] = {
    val xInt = x.toInt
    val yInt = y.toInt
    val kInt = k.toInt

    // Create a deep copy of the grid to avoid modifying the original
    val newGrid = grid.map(_.clone())

    // Iterate over the rows in the submatrix to be flipped
    for (i <- 0 until kInt) {
        val originalRow = xInt + i
        val flippedRow = xInt + kInt - 1 - i
        // Only flip if the original row is before the flipped row to avoid double flipping
        if (originalRow < flippedRow) {
            // Swap the relevant parts of the rows
            for (j <- yInt until yInt + kInt) {
                val temp = newGrid(originalRow)(j)
                newGrid(originalRow)(j) = newGrid(flippedRow)(j)
                newGrid(flippedRow)(j) = temp
            }
        }
    }

    newGrid
}
